{"content": "const PptxGenJS = require("pptxgenjs");
const path = require("path");
const fs = require("fs");

const pptx = new PptxGenJS();
pptx.author = "贾维斯";
pptx.title = "常记呱呱生产基地建设项目方案";
pptx.layout = "LAYOUT_WIDE"; // 13.33" x 7.5"

const W = 13.33;
const H = 7.5;

// ========== 配色方案：暖陶土红 + 鼠尾绿 ==========
const C = {
  red:      "B85042",   // 暖陶土红 — 主色
  redDark:  "8B3A2E",   // 深陶土红
  sage:     "7A9E7E",   // 鼠尾绿 — 辅色
  sageLight:"A7BEAE",   // 浅鼠尾绿
  cream:    "F5F0E8",   // 米白
  white:    "FFFFFF",
  dark:     "2C2C2C",
  dark80:   "3A3A3A",
  gray:     "9A9A9A",
  gold:     "C9A96E",
  overlay:  "1A1A1A",   // 图片暗层
};

// ========== 图片目录 ==========
const IMG_DIR = "/Users/东盛工作/5常记呱呱项目/图片合集";
const img = (name) => path.join(IMG_DIR, name);

// ========== 工具函数 ==========

// 全版图片背景 + 暗色蒙层
function addImageBg(slide, imagePath, opacity = 55) {
  slide.addImage({ path: imagePath, x: 0, y: 0, w: W, h: H, sizing: { type: "cover", w: W, h: H } });
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: 0, w: W, h: H,
    fill: { color: C.overlay, transparency: 100 - opacity },
  });
}

// 左侧色条
function addBar(slide, x, y, h, color) {
  slide.addShape(pptx.ShapeType.rect, {
    x: x, y: y, w: 0.08, h: h,
    fill: { color: color || C.sage },
  });
}

// 页面编号
function addPageNum(slide, num, total) {
  slide.addText(`${num}/${total}`, {
    x: W - 0.9, y: H - 0.45, w: 0.7, h: 0.3,
    fontSize: 10, color: C.gray, align: "right", fontFace: "Arial",
  });
}

// 章节号标签
function addChapterTag(slide, num, label) {
